            while (!dq.empty() && A[dq.back()] < A[i]) dq.pop_back();
            dq.push_back(i);
            if (i >= X - 1) {
                cout << A[dq.front()];
                if (i != N - 1) cout << ' ';
            }
        }
        cout << '\n';
    }
    return 0;
